INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "カリン", 0, 190804, 1, 0, 1, "", "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 2, "", "今日の運勢は姫吉！　あらゆる運気が最大を示しています！　　　今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 3, "", "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 4, "", "今日の運勢は姫吉！　その高い運気はまさにショーグンの如く！　その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 5, "", "今日の運勢は大吉！　運気がどんどん高まっています！　　　　　何をやっても、最大効率で素晴らしい結果になりますよ♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 6, "", "今日の運勢は大吉！　なにをやっても上手くいって大活躍！　　　そんな素敵なあなたを見て、後ろから誰かが……クスクス♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 7, "", "今日の運勢は大吉！　運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！　目指せヒデサ……ではなく秀才！", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 8, "", "今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたいやき！　和菓子パワーで売上アップです！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 9, "", "今日の運勢は中吉！　旅行運がぐんぐんと上昇中♪　　　　　　　もしかしたら、あの「マホマホ王国」にだって行けるかも♪", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 10, "", "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 11, "", "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 12, "", "今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 13, "", "今日の運勢は小吉！　早朝に幸運の兆しあり！　　　　　　　　　もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 14, "", "今日の運勢は小吉！　運気上昇中ですが、上がるまでが要注意！　ラッキーアニマルは熊！　本当の家族のように守ってくれるかも♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 15, "", "今日の運勢は小吉！　外に出てゆっくり過ごすと運気が上昇！　　ラッキースポットは牧場。面白い出会いがありそうです♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 16, "", "今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "", 0, 0, 0, 0, 17, "", "今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "カリン", 0, 190804, 2, 0, 18, "", "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60000, "カリン", 0, 190804, 3, 7, 19, "", "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ハツネ", 0, 101201, 1, 1, 20, "", "キミと出会ってもう\n1年もたつんだね！\nう～ん、いつも\n寝てばっかりだから、", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ハツネ", 0, 101201, 2, 1, 21, "", "少しでも\n寝る時間を減らして\nキミと一緒にいる\n時間増やしたいなぁ♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "シオリ", 0, 103801, 1, 1, 22, "", "あなたと知り合ってから\nもう1年…\n時がたつのは\n早いですね", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "シオリ", 0, 103801, 2, 1, 23, "", "来年も、\n一緒にいられたら…\nうれしいな", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "キョウカ", 0, 103601, 1, 2, 24, "", "あなたと一緒にいるようになって、\nもう1年ですか…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "キョウカ", 0, 103601, 2, 2, 25, "", "最初の頃よりも、頼もしく\nなりましたね。私はどうですか？\n成長していますか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミミ", 0, 102001, 1, 2, 26, "", "おにいちゃんとあってから、\n1年たったよ～！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミミ", 0, 102001, 2, 2, 27, "", "ミミね、おにいちゃんと\nいっぱい遊べてたのしかったな～♪\nこれからもずっと\nいっしょにいてね～！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミソギ", 0, 100401, 1, 2, 28, "", "にいちゃんがミソギのイタズラに\n引っかかり続けてもう1年かぁ", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミソギ", 0, 100401, 2, 2, 29, "", "…これからもいっぱいミソギと\n遊んでね、にいちゃん！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "マホ", 0, 101001, 1, 3, 30, "", "もう王子はんと会うてから\n1年ぐらいたつそうどすえ\n早いもんやなあ", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "マホ", 0, 101001, 2, 3, 31, "", "このままやと、\nうちもあっという間に\n干からびてしまいそうどすえ\nなーんてな。うふふ", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "イリヤ", 0, 104401, 1, 3, 32, "", "お主と会って早1年じゃな\nこれからも存分に尽くすがよい", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "イリヤ", 0, 104401, 2, 3, 33, "", "わらわもたまには、お主の献身に\n報いてやらぬでもない♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "カオリ", 0, 101701, 1, 3, 34, "", "もう、キミと出会って結構な時間が\nたつさ～。でも、私たちの旅は\nまだまだ始まったばかりさ～！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "カオリ", 0, 101701, 2, 3, 35, "", "これからも、どうぞよろしく\nお願いするさ～！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "サレン", 0, 102801, 1, 4, 36, "", "あんたと出会ってからもうそんなに\nたつのね～", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "サレン", 0, 102801, 2, 4, 37, "", "あっという間だったって感じるほど\n楽しかったわ！\nこれからも一緒に頑張りましょ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "スズメ", 0, 102501, 1, 4, 38, "", "出会ってから1年間、ずっと\nご迷惑をかけっぱなしで、\nすみません…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "スズメ", 0, 102501, 2, 4, 39, "", "これからはもっと頑張りますから\n見ていてくださいね\nできれば…\n今までよりも、私の近くで♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "タマキ", 0, 104601, 1, 5, 40, "", "振り返れば、今までいろんなことが\nあったにゃあ…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "タマキ", 0, 104601, 2, 5, 41, "", "これからも、二人でたくさんの\n思い出をがっぽり作っていく\nにゃー！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミフユ", 0, 104801, 1, 5, 42, "", "キミとの師弟関係も、\nもう1年なのね…\nでもキミに教えることは、", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミフユ", 0, 104801, 2, 5, 43, "", "まだまだいっぱいあるわ\nこれからも、\nしっかりついて来てね！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "アキノ", 0, 103201, 1, 6, 44, "", "あなたさまと出会ってもう1年…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "アキノ", 0, 103201, 2, 6, 45, "", "光陰矢のごとし、とはまさに\nこのことですわ。…思い出は決して\nお金では買えませんわね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ユカリ", 0, 103401, 1, 6, 46, "", "ダメな私を1年間も見捨てないで\nくれて、本当にありがとう", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ユカリ", 0, 103401, 2, 6, 47, "", "情けないところいっぱいみせるかも\nしれないけど、これからも一緒に\nいてくれると、うれしいな", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "クリスティーナ", 0, 107101, 1, 7, 48, "", "オマエと出会ってもう1年か\nまさかこのワタシの結婚相手に\nなろうとはな…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "クリスティーナ", 0, 107101, 2, 7, 49, "", "ともかくこれからも\n愉しませてくれよ☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ジュン", 0, 104701, 1, 7, 50, "", "君と出会ってからもう1年か。\n以前と比べて私の表情もいくらか\n柔らかくなった気がするんだが、\nどうだろう？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ジュン", 0, 104701, 2, 7, 51, "", "見えないから分からないって？\nそれもそうだな…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "トモ", 0, 103701, 1, 8, 52, "", "もう1年たったみたいだね\nあなたをからかってばかりだった\nけど、楽しかった♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "トモ", 0, 103701, 2, 8, 53, "", "これからもよろしくね！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "マツリ", 0, 100501, 1, 8, 54, "", "出会って、もう1年たっちゃった\nんスね。なんだか意外ッス", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "マツリ", 0, 100501, 2, 8, 55, "", "毎日楽しくて、あっという間に過ぎ\nちゃったみたいなんスよね\nこれからも一緒に悪と戦うッス！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミヤコ", 0, 100701, 1, 9, 56, "", "オマエと会って1年なの！\n全然成仏もできなかったし、", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミヤコ", 0, 100701, 2, 9, 57, "", "生き返りもしなかったけど、\nすごく楽しかったの～♪\nオマエとプリンがあれば、\nミヤコはハッピーなの～♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "シノブ", 0, 103101, 1, 9, 58, "", "あなたと出会って1年なんですね\nでも、私の占いでは、私とあなたは", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "シノブ", 0, 103101, 2, 9, 59, "", "来年も再来年も一緒にいるようです\nふふ、よろしくお願いしますね", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "アンナ", 0, 100901, 1, 10, 60, "", "貴様が閃光のシグルドとして覚醒し\nもう1年か…。これからも我らの\n長き戦いに終わりはないが、", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "アンナ", 0, 100901, 2, 10, 61, "", "それでも貴様となら…\n添い遂げる覚悟はできているぞ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ナナカ", 0, 101301, 1, 10, 62, "", "君と出会ってもう1年だって！\n早いねー！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ナナカ", 0, 101301, 2, 10, 63, "", "これからも最強のバディタッグで\n大活躍だー！\n頼りにしてるよ、相棒！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミツキ", 0, 105101, 1, 11, 64, "", "1年たつのって、あっという間ね\nまだまだ君の知らない部分が\nたくさんあるし…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ミツキ", 0, 105101, 2, 11, 65, "", "これからも、いろんなところを\n調べさせてね？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ルカ", 0, 105601, 1, 11, 66, "", "お前さんと出会ってもう1年か\n助太刀するつもりが", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ルカ", 0, 105601, 2, 11, 67, "", "逆に助けられたりもしたね\nこれからもよろしく頼むよ！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "エリコ", 0, 102701, 1, 11, 68, "", "早いものですわね、あなた様と\nお会いして、もう1年…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "エリコ", 0, 102701, 2, 11, 69, "", "あなた様といると、時があっと\nいう間に過ぎてしまいます\n時間を止める研究をしなくては\nいけませんね…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "アヤネ", 0, 102301, 1, 12, 70, "", "お兄ちゃんと会ってから、もう、\n1年なんだね。私、少しは\nお姉ちゃんっぽくなったかな？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "アヤネ", 0, 102301, 2, 12, 71, "", "あ、ぷうきちもお兄ちゃんっぽく\nなったよね？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "チカ", 0, 104201, 1, 12, 72, "", "あなたと出会って、\nもう1年がたったんですね…\nこれからもそばにいて、", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "チカ", 0, 104201, 2, 12, 73, "", "私のことを見守ってください\nできることなら、ずっと…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "クルミ", 0, 102101, 1, 12, 74, "", "お兄ちゃんと出会って1年かぁ\n私、相変わらずダメダメで…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "クルミ", 0, 102101, 2, 12, 75, "", "で、でもこれからもずっと…\n一緒にいたいなぁ…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "シズル", 0, 104901, 1, 13, 76, "", "再会してちょうど1年だね\nお祝いにごちそう作ってきたよ～♪\n特製ケーキと、お寿司と、", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "シズル", 0, 104901, 2, 13, 77, "", "ハンバーグと、カレーと、\nシチューと、あ、隠しきれない隠し\n味は、お姉ちゃんの愛情だよ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "リノ", 0, 101101, 1, 13, 78, "", "お兄ちゃんと再会して、もう1年\nなんですね。\n会えなかった時を思うと、", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "リノ", 0, 101101, 2, 13, 79, "", "信じられないくらい幸せな1年\nでした！もう絶対、私から離れ\nないでくださいね♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ユイ", 0, 100201, 1, 14, 80, "", "騎士クンと出会ってから今まで、\nいろんなことがあったよね\n楽しいこと、ドキドキしたこと…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ユイ", 0, 100201, 2, 14, 81, "", "そんな日々をこれからも、\nず、ずっと一緒に…\n過ごしていきたいな…！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ヒヨリ", 0, 100101, 1, 14, 82, "", "騎士くんと出会って、まだ1年しか\nたってないんだ！？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ヒヨリ", 0, 100101, 2, 14, 83, "", "なんかもうずっと一緒にいる気が\nするなぁ…えへへ。これからの\n1年もまたよろしくねっ！\n騎士くん！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "レイ", 0, 100301, 1, 14, 84, "", "初めてキミに出会って1年…\n随分見違えたね私もキミも、\n更に強くなっていく…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "レイ", 0, 100301, 2, 14, 85, "", "キミに背中を預けられる日が、\n早くきますように", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ペコリーヌ", 0, 105801, 1, 15, 86, "", "1年もわたしのことを、忘れない\nでいてくれて、ありがとうござい\nます！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "ペコリーヌ", 0, 105801, 2, 15, 87, "", "これからもずっと、覚えていて\nくださいね！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "コッコロ", 0, 105901, 1, 15, 88, "", "こうして1年も、主さまのおそばに\n置いていただけて、とても光栄\nです。どうかこれからも、", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "コッコロ", 0, 105901, 2, 15, 89, "", "末永く主さまをお世話させて\nください。わたくしは、ずっと\n主さまのガイド役でいたいのです", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "キャル", 0, 106001, 1, 15, 90, "", "1年か、まっさかこんなに長い\n付き合いになるなんてね～\nでも…わりと楽しい1年だったかも", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80001, "キャル", 0, 106001, 2, 15, 91, "", "だから、もうしばらくあんたに\n付き合ってやるわよ喜びなさい！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "スズメ", 0, 112101, 1, 0, 92, "", "新しい年のはじめに、\nおみくじはいかがでしょうか？\nよい運勢であるほど、\n沢山プレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 93, "", "今日の運勢は姫吉！　あらゆる運気が最大を示しています！　　　今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 94, "", "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 95, "", "今日の運勢は姫吉！　最強の運勢でどんなドジも跳ね除けます！　大切な人と一緒に、最高の一日になること間違いなし！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 96, "", "今日の運勢は姫吉！　どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！　新しい一歩を踏み出そう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 97, "", "今日の運勢は姫吉！　その高い運気はまさにショーグンの如く！　その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 98, "", "今日の運勢は大吉！　運気がどんどん高まっています！　　　　　何をやっても、最大効率で素晴らしい結果になりますよ♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 99, "", "今日の運勢は大吉！　なにをやっても上手くいって大活躍！　　　そんな素敵なあなたを見て、後ろから誰かが……クスクス♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 100, "", "今日の運勢は大吉！　ラッキーワードは「ちぇる～ん♪」　　　　出会う人みんなに言ってあげると、ハッピーになれますよ！", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 101, "", "今日の運勢は大吉！　運勢はバッチリで無敵状態！　　　　　　　龍眼で全てを見通して、思い通りの一日を過ごしましょう！", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 102, "", "今日の運勢は大吉！　運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！　目指せヒデサ……ではなく秀才！", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 103, "", "今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたいやき！　和菓子パワーで売上アップです！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 104, "", "今日の運勢は中吉！　旅行運がぐんぐんと上昇中♪　　　　　　　もしかしたら、あの「マホマホ王国」にだって行けるかも♪", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 105, "", "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 106, "", "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 107, "", "今日の運勢は中吉！　お出かけした先で良縁に恵まれそうです！　ダウナー系あざとい女子が、あま～い飴をくれるかも？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 108, "", "今日の運勢は中吉！　大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 109, "", "今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 110, "", "今日の運勢は小吉！　早朝に幸運の兆しあり！　　　　　　　　　もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 111, "", "今日の運勢は小吉！　運気上昇中ですが、上がるまでが要注意！　ラッキーアニマルは熊！　本当の家族のように守ってくれるかも♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 112, "", "今日の運勢は小吉！　外に出てゆっくり過ごすと運気が上昇！　　ラッキースポットは牧場。面白い出会いがありそうです♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 113, "", "今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 114, "", "今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 115, "", "今日の運勢は小吉！　思わぬ相手と仲良くなれるかも？　　　　　うっかり毒舌をもらしてしまわないように要注意です！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "", 0, 0, 0, 0, 116, "", "今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "スズメ", 0, 112101, 2, 0, 117, "", "おみくじの結果はいかがでしたか？\n新たに始まる一日が、\nあなたにとってよい日になりますように\n明日もお待ちしていますね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60001, "スズメ", 0, 112101, 3, 7, 118, "", "おみくじ、楽しんで頂けましたか？\nあなたの新しい年が\n素晴らしいものになるよう、\n心からお祈りしますね", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 1, 1, 119, "", "ヒューヒュー♪\nドンドンパフパフー♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 1, 1, 120, "", "ひゅーひゅー\nどんどんぱふぱふー\nでございます", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 2, 1, 121, "", "さぁ、キャルさまもご一緒に\nどんどんぱふぱふいたしましょう", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 1, 1, 122, "", "え？　ちょっと\nいきなりなにっ？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 2, 1, 123, "", "ドンドンパフパフってなんなの？\nあたしにも分かるように\nちゃんと説明しなさいっての！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 2, 1, 124, "", "実はですねキャルちゃん！\nもうすぐわたしたちにとっての\n大切な節目──", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 3, 1, 125, "", "『プリンセスコネクト！\nRe:Dive』\n2.5周年なんですよ！\nやばいですね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 3, 1, 126, "", "ですからその日に向けて\n今から気分を盛り上げているのです", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 3, 1, 127, "", "ああ、そういえば\nそんな時期だっけ\nって言っても、もう少し先じゃない\n気が早いんじゃないの？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 4, 1, 128, "", "いいえ、キャルさま\nこういったお祝いは準備から\n楽しむものでございます\nそうですよね、ペコリーヌさま", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 4, 1, 129, "", "その通りです♪　というわけで！\nカウントダウンの始まりですよ！\nみんなで一緒に2.5周年に向けて\n盛り上がっていきましょー☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 4, 1, 130, "", "ド、ドンドンパフパフ～\nって何言わせんのよ！\nまったくもう、浮かれちゃってさ", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 5, 1, 131, "", "ふふ。キャルさまもワクワクして\nおいでのようですね\nそれでは主さま。大切な記念日まで\nどうぞご期待くださいませ", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 5, 2, 132, "", "記念日を盛り上げるったって\n一体どうしたらいいのよ？\nあたし、そういうの\n苦手なんだけど…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 1, 2, 133, "", "あら、キャルさん\nどうかなさいましたか？\n何かお困りのようですけど", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 6, 2, 134, "", "げっ…カリンじゃない\nなんでもないわよ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 2, 2, 135, "", "そうなのですか？\nキャルさんのことですからてっきり\n2.5周年をどう盛り上げたら\nいいか悩んでいるのかと…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 7, 2, 136, "", "分かってんじゃないのよ！？\nいっ、いや、違うけどね！\nあたしは別にそんなことで\n悩んでないわよっ？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 3, 2, 137, "", "ふふっ…\nこういう時は、真心を込めて\n気持ちをそのまま口にしたら\nいいのではないでしょうか？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 8, 2, 138, "", "気持ちを、ねぇ\nそれが一番難しいんじゃない…\nそもそも、あたしは記念日とか\n別にどうだっていいし", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 9, 2, 139, "", "…まあ、ペコリーヌもコロ助も\nやけに楽しそうだったから…\nこういうお祭り騒ぎみたいなのも\nたまにはいいかな、とは思うけど", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 4, 2, 140, "", "なるほどなるほど～\nキャルさんは【美食殿】で祝う\n2.5周年を心から楽しみに\nしている、ということですね！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 10, 2, 141, "", "はぁ！？\nどこ聞いたらそうなるのよ！\nあたしは別に楽しみになんか…！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 5, 2, 142, "", "キャルさんの心からの想い\nみなさんにも伝わったでしょうか？\n私も2.5周年が楽しみです！\n以上、カリンがお伝えしました！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 11, 2, 143, "", "心からの想いって何なのよ！？\n勝手に人の言葉を\n捻じ曲げんじゃないわよ！\nこのくそ眼鏡ーーーっ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 6, 3, 144, "", "ペコリーヌさま、もうすぐ\n記念日でございますね\nこういった節目というのは\n感慨深いものでございます", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 5, 3, 145, "", "色んな思い出が蘇ってきますね！\n楽しい出来事が\nいっぱいありました♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 7, 3, 146, "", "はい、そうでございますね\n主さまも【美食殿】の活動の他にも\nいろんなご経験をされたと\n聞いておりますよ", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 8, 3, 147, "", "たしか…ランドソルで話題沸騰と\nなっていた、魔法少女なるものに\nお会いになられたとか", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 6, 3, 148, "", "魔法少女って、あの美味しくって\n栄養たっぷりの大ヒット商品\n『魔法少女ソーセージ』の箱に\n描いてある女の子のことですか！？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 7, 3, 149, "", "あのソーセージ\n美味しいんですよね～♪\nわたしもたっくさん食べてますよ！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 9, 3, 150, "", "あとは、牧場に素敵な温泉が\n出来たとか…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 8, 3, 151, "", "牧場ですか！？　温泉につかって\nチーズもオツですね～♪　考えた\nだけでよだれが出ちゃいそうです！\nやばいですね☆", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 10, 3, 152, "", "ペコリーヌさま\n言ってるそばからよだれが…\n今お拭きしますね。ふき、ふき", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 9, 3, 153, "", "えへへ、ありがとうございます\nコッコロちゃん！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 11, 3, 154, "", "それにしても、主さまは\n【美食殿】の一員として様々な\n美食と出会われていたのですね\nわたくし、感服いたしました", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 10, 3, 155, "", "これからもたくさん冒険をして\nめいっぱい美食を\n味わい尽くしましょうね！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 11, 4, 156, "", "2.5周年カウントダウン♪\nキャルちゃんキャルちゃん！\nわくわくしますね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 12, 4, 157, "", "あぁもう、うるさいわね～\nまだまだ先でしょ？\nちょっとは落ち着きなさいよ", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 12, 4, 158, "", "キャルちゃんだって最近\nソワソワしてるじゃないですか～\nさっきもご機嫌そうに鼻歌とか\n歌ってましたよね？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 13, 4, 159, "", "なっ…！　き、聞いてたの！？\nじゃない、歌ってないわよ！？\nあんたいい加減なこと言うと\nぶっ殺すわよ！？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 13, 4, 160, "", "えっへへ～♪\nわたしは最近のキャルちゃんが\nもっともっと大好きですよ♪\nすごく積極的になりましたよね！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 14, 4, 161, "", "…積極的？\nなんの話よ？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 14, 4, 162, "", "またまた～♪\nアイドルを目指そうとしたこと\n忘れちゃったんですか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 15, 4, 163, "", "ムーサの町で\nきゃるきゃる～ん☆　って！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 15, 4, 164, "", "あっ…！？　ちちち違うわよっ！\nあれは操られてただけで\nあたしはアイドルなんか\n目指してないっての！！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 16, 4, 165, "", "本当に本当ですか？\nわたし、キャルちゃんとっても\n乗り気だなって\n思ってたんですけど～", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 16, 4, 166, "", "まぁ、悪くはなかったけど…って\nだ、だから目指してないって\n言ってるでしょ！！\nなんてこと思い出させんのよ！？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 17, 4, 167, "", "ああ…ダメだわ…\nもう殺すしかない…\n2.5周年が来る前に\n記憶ごと消し去ってやるー！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 18, 5, 168, "", "2.5周年まであと10日…\nふ～ん？\n案外早いもんね？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 12, 5, 169, "", "そうでございますね…\nその日のためにやるべきことは\nまだまだございます\n気を引き締めねばなりません…！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 19, 5, 170, "", "やる気十分ねコロ助…\nそんな気負ってるとしんどいわよ？\nお気楽にやりましょ？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 13, 5, 171, "", "キャルさま…\nありがとうございます\nキャルさまは本当に\n優しいおかたです", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 20, 5, 172, "", "な、なにわけの分かんないこと\n言ってんのよ…\nあたしは優しくなんかないっての", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 14, 5, 173, "", "そんなことはございません\n…あの、実はわたくし\nキャルさまに\nひとつお願いがございまして", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 21, 5, 174, "", "お願い？　珍しいわね\nコロ助がそんなこと言うなんて\n…まあ、あたしに出来ることなら\n別にいいけど", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 15, 5, 175, "", "ありがとうございます\n実は記念日へ向けて\n『かくし芸』というものを\n用意してみようかと思いまして", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 22, 5, 176, "", "かくし芸？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 16, 5, 177, "", "はい。きゃるきゃる～ん☆　を\n参考に、ころころ～ん☆　という\nご挨拶を考えてみたのですが\nポーズがうまくいかなくて…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 23, 5, 178, "", "～～！！　ちょっと褒められて\nいい気になって損したわ！！\nふざけんなふざけんな\nふ～ざ～け～ん～な～っ！！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 17, 6, 179, "", "あと９日！　もうすぐですよ♪\nえへへ、楽しみで楽しみで\nごはんが進みますね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 24, 6, 180, "", "ごはんが進みますね☆\nじゃなーい！\nいくらなんでも食べ過ぎよ！\n記念日、迎えられなくなるわよ！？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 17, 6, 181, "", "大丈夫ですよキャルさま\n食事はわたくしたちの\n歩んできた道そのもの\nなのですから", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 18, 6, 182, "", "さっすがコッコロちゃん\nいいことを言いますね！\nそう、わたしたち\n【美食殿】の活動目的は─", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 25, 6, 183, "", "─みんなで楽しく食事をすること\nでしょ？\nあれだけ食べ歩いてきたんだから\n分かってるわよ", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 18, 6, 184, "", "はい…そうでございますね♪\nそれにしてもわたくしたち\n本当にいろいろなものを\n食べ歩いてきましたね…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 26, 6, 185, "", "そうね…ほんっとうにね…\n毒まみれのニセドラゴンとか\n恐竜…は逃げられちゃったっけ\nあとワニゴ…ワニの魔物とかね", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 27, 6, 186, "", "そして、とうとう本物の\nドラゴンまで相手に\nしちゃったのよね、あたしたちって", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 28, 6, 187, "", "信じられない強さだったわね\nあのドラゴン…やっぱり\n作戦はしっかり立てていかないと\nダメよね", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 19, 6, 188, "", "えへへ…☆\nキャルちゃんが色んなことを\n覚えていてくれて\nうれしいです♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 19, 6, 189, "", "わたくしも鮮明に覚えておりますよ\n主さまもきっと…♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 29, 6, 190, "", "あったり前でしょ！\n忘れないわよ、あんな滅茶苦茶な\nものばかり食べさせられて！\n…忘れられるわけ、ないじゃない", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 30, 7, 191, "", "ねえちょっと、ちょっと待って！？\nカリンから、2.5周年記念の\n生放送に出演してほしいって\n言われたんだけど！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 31, 7, 192, "", "なんでそういう大事なことを\n急に言うわけ！？\nそんなの聞いてないわよ～！？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 32, 7, 193, "", "いっぱい人に見られちゃうのよね？\nなんであたしがそんなこと…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 33, 7, 194, "", "あー\nあー\n…声、これで大丈夫かしら？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 34, 7, 195, "", "聞き取りにくいかもしれないわね…\nもうちょっと明るい方がいいかも\nえっと…こんな感じ？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 35, 7, 196, "", "オイッスー☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 36, 7, 197, "", "……\nいや、ないわ\nいつもどおりが一番ね、うん", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 37, 7, 198, "", "もう、記念の生放送なんて\n超責任重大なやつじゃない…\nもしなにか失敗とかしたら…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 38, 7, 199, "", "ど、どど、どうしよう！？\n緊張してきちゃった…！！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 20, 8, 200, "", "主さま、わたくし\nペコリーヌさまとキャルさまと共に\n2.5周年を祝う生放送に\n出演する大役を仰せつかりました", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 21, 8, 201, "", "多くの方々に\n『プリンセスコネクト！\nRe:Dive』の魅力をお伝えする\n重要な役割でございます", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 22, 8, 202, "", "わたくし、全身全霊をもって\n生放送に取り組みたいと\n思っております", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 23, 8, 203, "", "ですが、もしかしたら\nセリフを噛んでしまったり\n段取りを間違えてしまったり\nするかもしれません…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 24, 8, 204, "", "そのようなことがないよう\n練習はしっかりしておかなくては\nまずはこちらから…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 25, 8, 205, "", "オイッスー☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 26, 8, 206, "", "先ほどキャルさまが練習されて\nいるのをお見かけしたので\nわたくしもと思いまして…\nいかがでしょうか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 27, 8, 207, "", "良い感じ、ですか？\n…ふふ、ありがとうございます\n主さまのあたたかいお言葉があれば\nわたくしは百人力でございます", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 28, 8, 208, "", "この大役を無事に成し遂げ\n主さまに素敵な2.5周年を\n迎えていただけるよう…\nわたくし、尽力いたしますね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 20, 9, 209, "", "オイッスー☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 21, 9, 210, "", "…う～ん、今のはちょっと\n違う感じがしますね\n堅苦しかったかもしれません", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 22, 9, 211, "", "あと６日で2.5周年ですか…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 23, 9, 212, "", "この年月がオイッスーの\n歴史なんだと思うと\nじ～んとしちゃいます！\nやばいですね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 24, 9, 213, "", "生放送で最高のオイッスー☆　を\nみなさんにお届けするために\n頑張らないと！\nそれじゃあもう一度…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 25, 9, 214, "", "オイッスー☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 26, 9, 215, "", "…うう～ん、どうしてでしょう\nまだ何かが違う気がします…\nもしかしたら\nおなかが空きすぎてるとか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 27, 9, 216, "", "今さっき食べたばっかりですけど\nおなかが減っては\n良いオイッスー☆　は\n出せませんよね！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 28, 9, 217, "", "そうと決まれば、コッコロちゃんと\nキャルちゃんを誘って\nごはんにしましょう！\n善は急げです！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 29, 9, 218, "", "あ、二人が丁度いいところに！\nオイッス～☆　…ああ！！\n今の、今のですよ～♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 30, 9, 219, "", "なるほど、どんな時も\n自然体が一番ってことですね！\nこの調子で、生放送も\n頑張っちゃいます♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 31, 10, 220, "", "2.5周年まで残り５日ですが\nその前にもうすぐ生放送ですよ！\nコッコロちゃん\n準備の方はどうですか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 29, 10, 221, "", "はい。わたくし、しっかりと\n備えてまいりました\n万事抜かりはございません", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 32, 10, 222, "", "おお～すごい自信を感じます…！\nいい生放送になりそうですね☆\n……あれ？　なんだかこの辺り\n揺れていませんか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 39, 10, 223, "", "…………", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 30, 10, 224, "", "キャルさま？\nお風邪をひかれたんでしょうか\nひどい震えですが…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 40, 10, 225, "", "かかかか風邪じゃないわよ！\nここここれはただ\nななな生放送が楽しみ過ぎて\nワワワワクワクが止まらないだけ！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 33, 10, 226, "", "大丈夫ですかキャルちゃん！？\nそうだ、これを飲んでください！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 41, 10, 227, "", "きき気がきくじゃない、ありがとっ\nごくっ、んく…ぶはぁっ！？\nちょっと何飲ませたの！？\n辛っ！　苦ぁ！？　甘ぁっ！？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 34, 10, 228, "", "これは魔物のエキスに薬草に\nその他色んなものを混ぜた\n特製の栄養ドリンクです！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 35, 10, 229, "", "これを飲めば体ぽかぽかで\n元気いっぱいですよ♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 42, 10, 230, "", "このアホリーヌ！\n風邪じゃないって言ったでしょ！？\nどさくさに紛れて\nそんな恐ろしいもん飲ませんな～！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 31, 10, 231, "", "キャルさま\n震えが収まっておりますね\nよかったです…\nわたくし、心配いたしました", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 43, 10, 232, "", "え？　ああ、ホントね…って\nだから風邪じゃないって\n言ってるのに…\nまあいいわこの際なんでも", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 36, 10, 233, "", "えっへへ～♪　いつも通りの\nキャルちゃんに戻りましたし\n素敵な生放送が出来そうですね！\n今から楽しみです☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 6, 11, 234, "", "ランドソルのみなさま、こんにちは\n生放送の会場設営を担当しています\n【ギルド管理協会】のカリンです", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 7, 11, 235, "", "【美食殿】のみなさんは\nまもなく始まる生放送に向けて\n最後の調整のため\n席を外しています", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 8, 11, 236, "", "頑張っている３人の\n邪魔をするわけには\nいきませんので、ご容赦ください", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 9, 11, 237, "", "ですので、本日は私から\n【美食殿】のみなさんの様子を\nお伝えさせていただこうと思います", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 10, 11, 238, "", "まずはペコリーヌさんですが…\n何やら大量のおにぎりを\n食べているようです\nえっと…栄養は大事ですよね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 11, 11, 239, "", "次にコッコロさんですが\nこちらは発声練習をしています", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 12, 11, 240, "", "一生懸命、小さなお口を開けて\n声を出す姿が応援したくなりますね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 13, 11, 241, "", "そしてキャルさんは…\nこれは…堂々としたものですね\n何もせず、ただ立ち尽くして…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 14, 11, 242, "", "あれ？\nもしかして緊張で気を失って…？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 15, 11, 243, "", "…ええと\n【美食殿】のみなさんは\nやる気十分なようですね！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 16, 11, 244, "", "３人とも生放送を\nいいものにしようと\n全力で頑張ってくれていますので\nどうかご期待ください", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 17, 11, 245, "", "それでは\nまた明日お会いしましょう♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 44, 12, 246, "", "2.5周年まであと３日！\nそして生放送は明日！\nなんかいよいよって感じね…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 37, 12, 247, "", "３人でい～っぱい練習しましたし\nきっと大丈夫ですよ☆", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 32, 12, 248, "", "ペコリーヌさまに\n大丈夫と言ってもらえると\nとても心強いですね", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 45, 12, 249, "", "信じすぎちゃだめよコロ助\nこいつはなーんにも\n考えてないだけなんだから", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 38, 12, 250, "", "ひどいですよぉキャルちゃ～ん！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 33, 12, 251, "", "ふふ。お二人とも\n普段通りの様子で\n安心いたしました", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 39, 12, 252, "", "はいっ☆\n生放送でもなんでも\n全力全開、わたしらしく\nぶつかっていくだけです！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 46, 12, 253, "", "そうね。おめでたいことなんだし\nここまで来たんなら\n楽しめるだけ\n楽しむしかないわよね！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 34, 12, 254, "", "わたくしも、普段よりも心が\n熱くなっております\nこの胸の気持ちをお伝えできるよう\n精一杯努力いたします…！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 40, 12, 255, "", "それでは、いきましょう！\n明日の生放送、絶対に\n成功させましょうね☆", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 41, 13, 256, "", "えっと、最初のひと言は…あれ？\nキャルちゃん、わたし\n何て言うんでしたっけ？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 47, 13, 257, "", "は！？\nなにいきなりど忘れしてるの！？\nっていうかあんた、台本は！？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 42, 13, 258, "", "忘れてきちゃいました☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 48, 13, 259, "", "忘れてきちゃいました☆\nで済ませられると思ってんの！？\nほら、あたし二冊持ってきたから\nこれ使いなさい！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 35, 13, 260, "", "マイクとは、こんな高い位置に\nあるものなのですね…！\n背伸びをすれば、何とか…\nう～ん、うぅ～ん…！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 49, 13, 261, "", "あぁもう\n少し下げればいいでしょ！？\nこれくらいでいい？\nまったく、世話が焼けるわね…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 43, 13, 262, "", "あれ？\nキャルちゃん、後ろ髪が\nはねちゃってますよ？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 50, 13, 263, "", "え？　うそっ！？\nちゃんと確かめてきたのに！\nどこどこ！？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 36, 13, 264, "", "キャルさま、動かないで\nくださいまし。今くしで…\nはい、直りましたよ", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 51, 13, 265, "", "あ、ありがと…はぁ。生放送\n本番までもうすぐなのに\nこんなことしてる場合じゃ\nないわよね", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 37, 13, 266, "", "はい、時間は残りわずかです\nですが、慌ただしく\n動き回るこの時間も\nなんだか楽しくて…♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 52, 13, 267, "", "コロ助、あんた…って\nそうじゃなくて！\n胸にジンワリきてる\n暇なんかないでしょ…！？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 44, 13, 268, "", "あはは♪\nキャルちゃんの動きが\nとっても面白いです♪\nやばいですね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 38, 13, 269, "", "ふふ\nきっと面白い生放送になると\nわたくし、確信しております", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 45, 13, 270, "", "絶対絶対、間違いありません！\n見てくれるみなさんが\n笑顔になれる時間を\nお届けしましょう！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 53, 13, 271, "", "そんなの当然でしょ！\n誰が見たって面白いって\n言ってもらえるように\nあれだけ準備したんだから！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 46, 13, 272, "", "それでは\n記念日直前生放送！\n楽しみにしててくださいね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 18, 14, 273, "", "こんにちは\n【ギルド管理協会】のカリンです", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 19, 14, 274, "", "昨日の生放送は\nいかがだったでしょうか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 20, 14, 275, "", "たくさんの笑顔と喜びと\nそして驚きを受け取って\nいただけたのではないかと思います", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 21, 14, 276, "", "そしていよいよ\n明日は2.5周年の当日\n待ちに待った記念日を\n迎えることとなります", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 22, 14, 277, "", "【美食殿】のみなさんも\n張り切って様々な準備を\nされていますよ", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 23, 14, 278, "", "【ギルド管理協会】も\n万全のサポート体制で\n協力してまいりたいと思います", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 24, 14, 279, "", "…ふふ、本当に楽しみですね\n【ギルド管理協会】の職員として\nだけではなく、私個人としても…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 25, 14, 280, "", "この記念日を迎えられることが\n心から楽しみですし\n幸せを感じています", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 26, 14, 281, "", "きっと【美食殿】のみなさんは\nそれ以上に心を弾ませて\nいることでしょう", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "カリン", 0, 190801, 27, 14, 282, "", "それでは\n明日からの2.5周年を\nどうぞ、お楽しみに…♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 47, 15, 283, "", "準備はいいですかっ？\n…いっきますよー！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 54, 15, 284, "", "祝！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 39, 15, 285, "", "2.5周年！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 48, 15, 286, "", "おめでとうございま～す☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 55, 15, 287, "", "少し前まではまだまだ先じゃない\nとか言ってたけど\n本当にあっという間だったわね", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 40, 15, 288, "", "光陰矢の如し…\nとはこのことでございますね\nでも、今日という日を無事に\n迎えることができて良かったです", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 49, 15, 289, "", "コッコロちゃん！　キャルちゃん！\n落ち着くには\nまだ早いですよ！\n盛り上がるのはこれからです☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 56, 15, 290, "", "ほんとあんたはいつも\n全力全開ねー\nでもそうね、記念日なんだし\nパーっといきましょ！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 41, 15, 291, "", "ええ、わたくしも全力全開で\nまいります…！\n主さま、さあ\nどうぞ手を取ってくださいまし…♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 57, 15, 292, "", "あんたもコロ助も、浮かれて\n転ぶんじゃないわよ？\n…仕方ないから、あたしも\n手を繋いであげるわよ", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 50, 15, 293, "", "あー！　二人ともずるいです！\nわたしもっ、ギュー♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 58, 15, 294, "", "ちょっ、ペコリーヌ！\nくっつき過ぎよ！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 51, 15, 295, "", "記念日だから\n平気平気♪\nやばいですね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 59, 15, 296, "", "意味分かんないわよ！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 42, 15, 297, "", "ふふ。このめでたき日に\n喜びがあふれておりますね\n主さまは…いかがでしょうか？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 43, 15, 298, "", "喜んでいただけているならば\nわたくしはとてもとても\n幸せでございます", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 52, 15, 299, "", "さぁ、2.5周年を\n楽しみ尽くしますよ☆\nまだまだ食べたいものもありますし\nやりたいこともたくさんです！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "キャル", 0, 106001, 60, 15, 300, "", "分かった、分かったから\n引っ張るんじゃないわよ！\n…そんな掴まなくても\nちゃんとついていくから", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "コッコロ", 0, 105901, 44, 15, 301, "", "ペコリーヌさま…キャルさま…\n主さま…共にまいりましょう\nどこまでも…！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ", 0, 105801, 53, 15, 302, "", "はい！　それでは2.5周年\n食べつくしツアーへ！\nそして、その先の未来へ\n向かって出発しましょう！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80003, "ペコリーヌ・コッコロ・キャル", 1, 105801, 54, 15, 303, "105901,45,106001,61", "2.5周年\nありがとうございます！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "カリン", 0, 190804, 1, 0, 304, "", "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 305, "", "今日の運勢は姫吉！　どんな不可能も可能にできちゃう！　　　　仲間と食卓を囲めばさらに運気上昇よ！　ただし魔物料理以外！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 306, "", "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 307, "", "今日の運勢は姫吉！　最強の運勢でどんなドジも跳ね除けます！　大切な人と一緒に、最高の一日になること間違いなし！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 308, "", "今日の運勢は姫吉！　どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！　新しい一歩を踏み出そう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 309, "", "今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 310, "", "今日の運勢は大吉！　お裁縫好きな女の子のお墨付きです！　　　お世話したがりの妹にめいっぱい愛されちゃうかも！？", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 311, "", "今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 312, "", "今日の運勢は大吉！　ラッキーワードは「ちぇる～ん♪」　　　　出会う人みんなに言ってあげると、ハッピーになれますよ！", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 313, "", "今日の運勢は大吉！　運勢はバッチリで無敵状態！　　　　　　　龍眼で全てを見通して、思い通りの一日を過ごしましょう！", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 314, "", "今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 315, "", "今日の運勢は中吉！　家の中でゆっくり過ごすのがよさそう！　　ラッキーアイテムはゲームよ！　ベストスコアを更新できるかも？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 316, "", "今日の運勢は中吉！　上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 317, "", "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 318, "", "今日の運勢は中吉！　日頃の努力が報われます！　　　　　　　　親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 319, "", "今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたい焼き！　和菓子パワーで売上アップです！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 320, "", "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 321, "", "今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかのごとく、色々な事がうまくいきますよ♪", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 322, "", "今日の運勢は小吉！　まだ見ぬ危険が隠れているかも！　　　　　でも安心しろ！　提督が貴公を守ってくれるはずだぞ！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 323, "", "今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 324, "", "今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 325, "", "今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 326, "", "今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 327, "", "今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "", 0, 0, 0, 0, 328, "", "今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "カリン", 0, 190804, 2, 0, 329, "", "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60002, "カリン", 0, 190804, 3, 7, 330, "", "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 1, 1, 331, "", "ささ、シェフィさまはこちらへ…", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 1, 1, 332, "", "コッコロさん、どこへ行くの…？\n…え？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 1, 1, 333, "", "『おめでとうございます！\nわ～パチパチー！』\n…という感じでどうですかね！？", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 2, 1, 334, "", "ではわたくしも\n後ろからクラッカーを鳴らして\n応戦いたします\nああ、当日が待ち遠しいですね", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 2, 1, 335, "", "ええと…\n二人とも何をしているの？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 1, 1, 336, "", "シェフィは初めてだもんね\nあの日が近いからって\n予行練習してんのよ\n気が早いわよね～", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 3, 1, 337, "", "あの日…？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 2, 1, 338, "", "その通りです…\nいよいよ記念すべきあの日が\n近づいてきましたよ！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 3, 1, 339, "", "『プリンセスコネクト！\nRe:Dive』3.5周年！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 1, 1, 340, "", "やばいですね☆", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 2, 1, 341, "", "って、なにしれっと\n参加してんのよカリン！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 2, 1, 342, "", "ふふ、いいじゃないですか\n【ギルド管理協会】として\n私もみなさんと一緒に\nお祝いをさせてください！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 3, 1, 343, "", "それに…記念日が近づけば\nとっておきの情報を\nお届けしますから♪", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 4, 1, 344, "", "というわけで\n今日からシェフィちゃんも一緒に\nカウントダウンしちゃいましょう！\n3.5周年まで…", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 4, 1, 345, "", "えっ！？　ええとええと…！\nあ、あと14日…！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 5, 2, 346, "", "3.5周年まであと13日\n豪華に、そして盛大に\nお祝いしたいですね☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 3, 2, 347, "", "豪華といえば前にとある貴族さまが\n舞踏会を開かれたそうで\n主さまがそのお手伝いを\nしておりました", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 4, 2, 348, "", "そこで美しい所作を学ばれたので\nわたくしも教えていただきました\nしゃなり、しゃなり…\nいかがでしょう？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 6, 2, 349, "", "すっごく上手ですよ☆\nまるでお姫様みたいです\nせっかくなのでわたしも\nしゃなりしゃなり", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 5, 2, 350, "", "さすがでございます\nペコリーヌさま", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 3, 2, 351, "", "いや、あんたは\nできなきゃダメでしょ\n本物のお姫様なんだし", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 5, 2, 352, "", "しゃなり、しゃなり…\nふふ、案外できるものね", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 7, 2, 353, "", "わぁ！\nシェフィちゃん\n姿勢がとってもキレイです♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 6, 2, 354, "", "さ、次はキャルさまの\n番でございますよ", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 4, 2, 355, "", "あ、あたしはいいわよ！\nそういうの全然分かんないし…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 6, 2, 356, "", "大丈夫\nやってみると結構楽しいわよ\nほらほらっ", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 5, 2, 357, "", "そ、そこまで言うなら…\nしゃなにゅわきゃあっ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 6, 2, 358, "", "いたたた…もぉお～！\nなんであたしがこんな目に～！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 7, 2, 359, "", "まぁまぁ\n記念日までに練習すれば\nできるようになるかもしれません\nよろしければお教えいたしますよ", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 7, 2, 360, "", "よし！\nあんたたちができて\nあたしだけできないのはしゃくだし\nやってやろうじゃないの！！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 8, 3, 361, "", "3.5周年まであと12日\n記念日当日はもちろんですが\nその日を待つ時間というのも\n心躍ります", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 8, 3, 362, "", "分かりますっ！\nどんな特別な料理を食べられるのか\n考えるだけでワクワクしますよね！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 9, 3, 363, "", "特別な料理といえば、お祭りですね\nそういえば主さまは学生として\n聖学祭に参加されたこと\nがあるとか…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 7, 3, 364, "", "聖学祭…って、なにかしら？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 10, 3, 365, "", "聖テレサ女学院の祭典ですよ\n二つのチームが競い合い\n青春を満喫するのが趣旨のようです", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 8, 3, 366, "", "それってカルミナの\nサプライズライブがあった\nお祭りよね？\nちょっと見たかったかも…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 9, 3, 367, "", "カルミナの後の\nライブも好評だったらしいじゃない\n確か、なかよし部\nだったっけ…？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 9, 3, 368, "", "なかよし部…\n仲が良さそうな名前で\nやばいですね☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 10, 3, 369, "", "いや、そのまんますぎでしょ…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 8, 3, 370, "", "聖学祭かぁ…なんだか楽しそうね\nそれになかよし部の人たちも\n気になるわ", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 10, 3, 371, "", "それじゃあわたしたちも、\n負けじと仲良くしましょう♪\nほらほらシェフィちゃん、\nぎゅーっ☆　ですよ♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 9, 3, 372, "", "えっ？　ええ…\nぎゅーっ…？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 11, 4, 373, "", "3.5周年まであと11日！？\nお祝いの準備進んでないんだけど…\nああ～昨日に戻りたいわ…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 10, 4, 374, "", "そういえばそんな魔道具があるって\n聞いたことがあるわね\n確か、名前はタイムラーベ…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 12, 4, 375, "", "なにそれヤバいわね\nでも本当にあるんだったら\n準備よりももっとやり直したいこと\nたくさんあるんだけど…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 11, 4, 376, "", "もしや正月の件でしょうか…？\nあの時はお金がなくて\n苦労しましたから", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 13, 4, 377, "", "あれはそうね…\nお金を湯水のように使う\nぺコリーヌを止められたら\nあんな苦労をすることもなかったし", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 11, 4, 378, "", "そんなこともありましたね！\nやり直したいといえば\n『きゃるきゃる～ん♪』\nの方かと思いましたよ！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 14, 4, 379, "", "バラすんじゃないわよ\nこのアホリーヌ！\nシェフィはそれ\n知らないんだから！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 15, 4, 380, "", "こうなったらもう、なんとか\nタイムラーべを探し出して\n今の会話をなかったことに…\nって、どうしたのよシェフィ", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 11, 4, 381, "", "うん…もし、私だったら…\n私が知らないみんなとの時間を\n見てみたいな、って…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 12, 4, 382, "", "シェフィちゃん！　タイムなんとか\nなんかなくても大丈夫ですよ！\n一緒の時間はこれから\nどんどん作ればいいんですから！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 12, 4, 383, "", "はい、今この瞬間も\n未来にはかけがえのない思い出に\nなっていることでしょう", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 16, 4, 384, "", "だからそんな顔しないの\nほら、お祝いの準備、進めるわよ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 12, 4, 385, "", "みんな…そうね\n最高のお祝いにして\n最高の思い出にしましょう！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 13, 5, 386, "", "3.5周年まで、あと10日！\nもうすぐですよー！\n楽しみすぎて、やばいですね！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 14, 5, 387, "", "そういえば…たくさんのおもちゃが\n子どもたちを襲うっていう\n騒動もありましたね…\nなんでも勝手に動き出したとか！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 15, 5, 388, "", "学校や孤児院とかに\nちっちゃなおもちゃが乗り込んで\n暴れたみたいですよ！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 17, 5, 389, "", "暴れたって言っても\n所詮はおもちゃじゃない\nどうせちっさいんでしょ？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 18, 5, 390, "", "だったら魔法で\n全部ぶっ飛ばせばいいじゃない！\n大したことないわよ！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 13, 5, 391, "", "キャルってば…\n相手は子どもが\n大事にしてる物なのよ…？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 13, 5, 392, "", "乱暴な発言は\nめっ、でございますよ？\n子どもの教育に悪影響を\n与えてしまいますから…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 16, 5, 393, "", "キャルちゃんだって\n意外と猫グッズとか\nたっくさん集めてますよね？\nもしその子たちが暴れたら…？", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 19, 5, 394, "", "う、うっさいわね！\n意外とか言うな！\n…ま、まあ確かに正面切って\n魔法でぶっ飛ばせないかもね…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 17, 5, 395, "", "あはは☆\nキャルちゃんのそういうところ\n好きですよ♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 18, 5, 396, "", "そんなキャルちゃんに猫グッズを\nプレゼントしちゃいますね！\n一部で流行っていた、たい焼き屋の\nおまけフィギュアですよ♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 19, 5, 397, "", "乱暴に扱ったりしないでくださいね\nひとりでに暴れ出しちゃうかも\nしれませんから！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 4, 6, 398, "", "3.5周年まであと９日\nここでみなさんに\nビックニュースですよ！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 5, 6, 399, "", "3.5周年を祝う生放送に\n去年と同様【美食殿】の\nみなさんにご出演いただくことが\n決定しましたー！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 20, 6, 400, "", "…えっ！？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 20, 6, 401, "", "本当ですか！？\nそれじゃ今から張り切って\n生放送中に食べる魔物料理を\n作らなくちゃですね☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 14, 6, 402, "", "いや…がんばるところは\nそこじゃないような…\nというか去年も出演してたのね\nすごいじゃない！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 14, 6, 403, "", "はい。とても緊張しますが\nやりがいのある大役です\n一緒にがんばりましょうね\nシェフィさま", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 15, 6, 404, "", "わ、私も出るの！？　でも…\n私も【美食殿】の一人だものね\nそれなら今からしっかり準備をして\nコンディションを整えないと…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 21, 6, 405, "", "ふふん♪\n生放送直前のカチコチになった\nシェフィの姿が楽しみだわ！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 21, 6, 406, "", "去年のキャルちゃんは\n緊張しすぎてずっと震えて\nかわいかったですもんね！\n今年もあの姿が見たいです！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 22, 6, 407, "", "ぶっ殺すぞ！？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 6, 6, 408, "", "というわけで\n『プリンセスコネクト！\nRe:Dive』の魅力を\nお伝えする生放送をお楽しみに♪", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 15, 7, 409, "", "3.5周年まであと８日\nでございますよ\n楽しみですね、主さま", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 23, 7, 410, "", "そういえばあんた\n夏休みの宿題は\nきちんとやってるの？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 16, 7, 411, "", "宿題…学校に通うのも\n楽しいことばかりじゃ\nないのね", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 22, 7, 412, "", "あれ？　そういえば\n少し前にルーセント学院で\n何かあったような…", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 24, 7, 413, "", "ああ、始業式の日に\n大捕り物があったって\n話題になってたわね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 17, 7, 414, "", "夏休みを終わらせないって\n騒いでたっていう話？\nあれ本当なの？\n都市伝説だと思ってたわ", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 16, 7, 415, "", "その一件ならよく存じ上げて\nおります。ですから主さま\n次の機会にはわたくしと一緒に\nがんばりましょう", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 18, 7, 416, "", "楽しそう…私も一緒にやりたいな\nママ…じゃ、じゃなくて！\nコッコロさん、私もまざっていい？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 17, 7, 417, "", "もちろんでございます\n仲良くお勉強いたしましょう", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 25, 7, 418, "", "しれっと教育ママが\n生まれてる…？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 23, 7, 419, "", "お勉強は大切ですよ！\nキャルちゃんも一緒に\nがんばりましょう！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 26, 7, 420, "", "え～～～～！？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 27, 8, 421, "", "3.5周年まであと７日〜♪\nふふ～ん♪\nふんふふ～ん♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 19, 8, 422, "", "…\nねぇコッコロさん\nキャル、どうしちゃったの？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 18, 8, 423, "", "とてもご機嫌そうに\n鼻歌を歌ってらっしゃいますね\n耳も尻尾もリズミカルに\n揺れて…ノリノリでございます", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 24, 8, 424, "", "あれはですね！\nカルミナのみなさんの\nサマーライブのチケットが\n手に入ったからなんですよ♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 20, 8, 425, "", "ええっ！？\nあのライブのチケットって確か\n入手困難だったんじゃ…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 28, 8, 426, "", "ふふふふ～ん♪\nしゃいにんぐふゅ～ちゃ～♪", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 19, 8, 427, "", "なるほど…\nキャルさまがあのように\nなってしまうのも頷けますね", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 21, 8, 428, "", "…カルミナの\n『Shining Future』\nの中に、シャイニングフューチャー\nって歌詞はなかったはずだけど…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 29, 8, 429, "", "ふんふ…はっ！？\nあっ、あんたたち！\nなに人の鼻歌を\n勝手に聞いてるのよ！？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 30, 8, 430, "", "こっ、これは別に\nカルミナの曲じゃなくて…\nあたしのオリジナルソングよ！\n聞いたらお金取るわよっ！？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 25, 8, 431, "", "えへへ、キャルちゃん\nカルミナのサマーライブ\n思いっきり楽しみましょうね☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 31, 8, 432, "", "も～っ！\n生暖かい目で見るな～～！\nぶっ殺すわよ～～～！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 22, 9, 433, "", "3.5周年まであと６日\n３人も言ってたけど\nあっという間だったわね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 23, 9, 434, "", "…えっ？\n生放送の意気込み！？\n突然なに！？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 24, 9, 435, "", "ええと…\nとにかく失敗しないように\n台本たくさん読んで…\nそれから…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 25, 9, 436, "", "えっ！？\nトラブルがあったら\nどうするのかって！？\nそ、それは…！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 26, 9, 437, "", "とにかく落ち着いて\nスタッフさんの指示を聞いて…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 27, 9, 438, "", "それから、それから…！\nぅ、ぅぅっ…！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 28, 9, 439, "", "―びえぇぇ～んっ！！！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 20, 9, 440, "", "どうされましたか、シェフィさま", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 29, 9, 441, "", "ううっ…ひっく…\nママッ…！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 21, 9, 442, "", "よしよし、緊張されてるのですね\nママが傍におりますよ\n主さま、少々お待ちくださいませ", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 22, 9, 443, "", "…ふぅ\nシェフィさま\n生放送への意気込み\nお話しできそうですか？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 30, 9, 444, "", "…ううっ\n恥ずかしすぎて\nもう生放送出られない…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 23, 10, 445, "", "主さま\n3.5周年まであと５日\nでございます", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 24, 10, 446, "", "ですがその前に\n生放送がありますね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 25, 10, 447, "", "…生放送に向けた\n意気込みでございますか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 26, 10, 448, "", "もちろんわたくしは\n主さまのために\n全身全霊を込めて\n楽しい時間をご提供いたします", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 27, 10, 449, "", "…と、意気込んでみましたが\nうまくできるか少し不安です\n声が小さくなったり\n間違えてしまったらどうしようと…", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 28, 10, 450, "", "ですがわたくしは\n一人ではありません\n【美食殿】のみなさまが\nおります", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 29, 10, 451, "", "どんな困難も\nみなさまと一緒なら\n乗り越えられると\nわたくし、確信しております", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 30, 10, 452, "", "それに今回はシェフィさまも\nご参加されるわけですし\nママとしてお手本に\nならねばなりませんね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 31, 10, 453, "", "主さま。3.5周年も\n食卓を囲んでいる時のような\n楽しい思い出を\n一緒に作りましょうね", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 26, 11, 454, "", "3.5周年まであと４日！\nやばいですね☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 32, 11, 455, "", "はいはい、やばいわね\nというかもうすぐ生放送だけど\nあんた準備はできてるの？", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 27, 11, 456, "", "ばっちりオイッスー☆　ですよ！\n『王家の装備』も全開です！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 28, 11, 457, "", "あとは前回を超える\n最高のオイッスー☆　を\nお届けできるように\n練習あるのみですかね！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 29, 11, 458, "", "キャルちゃんは\nどうなんですか？\nオイッスー☆　を\n毎日ちゃんと練習してますか？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 33, 11, 459, "", "はぁ！？　なんであたしまで\nその変なあいさつを練習しないと\nいけないのよ！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 30, 11, 460, "", "もしかしてやってないんですか？\nダメですよキャルちゃん！\nシェフィちゃんだってちゃんと\n毎日練習してるのに！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 31, 11, 461, "", "こうなったらわたしがキャルちゃん\nにオイッスー☆　の『オ』から\nしっかり教えてあげないと！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 32, 11, 462, "", "オイッスー☆　の『オ』は\n口を大きく開いて〜\nドラゴンの骨つき肉に\nかぶりつく直前をイメージして〜", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 34, 11, 463, "", "だからあたしはやるなんて一言も…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 33, 11, 464, "", "オイッスー☆", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 35, 11, 465, "", "聞きなさいっての！！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 31, 12, 466, "", "3.5周年まであと３日…\nそして生放送は、明日…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 32, 12, 467, "", "もっと台本を\n読み込んでおかないと…\nあと発声練習も…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 33, 12, 468, "", "おいっす！\n…こうじゃなかったわね\nええと確か…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 34, 12, 469, "", "うう…あんなに練習したのに\nこれじゃみんなに迷惑かけちゃう…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 35, 12, 470, "", "【美食殿】の一員として\n認められるように\n頑張らないといけないのに\nよし、もう一度…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 34, 12, 471, "", "やってますねシェフィちゃん！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 36, 12, 472, "", "なによ、考えることは\nみんな同じってこと？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 32, 12, 473, "", "ふふ。シェフィさま\nよろしければ\n仲間に入れてください\n一緒にやればきっとうまくできます", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 36, 12, 474, "", "みんな…もちろんよ！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 35, 12, 475, "", "それじゃ明日の生放送に向けて\n一緒に練習がんばりましょう☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 7, 13, 476, "", "3.5周年まであと２日と\n迫った本日は…\nいよいよ生放送です！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 8, 13, 477, "", "【美食殿】のみなさんが\n準備に入られていますので\nそれぞれ繋いでみましょう！\nまずはペコリーヌさんです！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 36, 13, 478, "", "今日もオイッスー☆\nみんなで一緒に\nオイッスー☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 9, 13, 479, "", "お手本になるような\n発声練習ですね！\nそれでは続いてコッコロさん", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 33, 13, 480, "", "はじめちょろちょろ\nなかぱっぱ～♪\n生放送前にみなさまで\n食卓を囲んで英気を養いましょう", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 10, 13, 481, "", "さすが【美食殿】のママですね！\nそしてキャルさんは…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 37, 13, 482, "", "大丈夫…大丈夫…\nあたしは大丈夫…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 11, 13, 483, "", "す、すごく震えてますけど\n大丈夫でしょうか…？\nそして今回初参加となる\n期待の新人シェフィさん！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 37, 13, 484, "", "あうー？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "みんな", 1, 105801, 37, 13, 485, "105901,34,106001,38,190801,12", "あ…", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 39, 13, 486, "", "ちょ、ちょっとシェフィ！？\nなに赤ちゃん返りしてん―\nあ痛ぁっ！\n噛んだわこいつーっ！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 35, 13, 487, "", "シェフィさま\n緊張しすぎて\nしまったのでしょうね…\nおーよしよし…", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 38, 13, 488, "", "シェフィちゃん！\nそういう時は手のひらに\n好きな文字を書いて\n食べちゃうといいですよ！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 13, 13, 489, "", "…ええと、現場からは以上です！\n生放送はもうすぐ！\n特別なお知らせもありますので\nどうぞお楽しみに！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 38, 14, 490, "", "3.5周年の記念日も\nいよいよ明日ね\n…って、あれ？", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 39, 14, 491, "", "記念日はこの森へ行きませんか！？\nすっごく美味しいお肉が\nとれるんです☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 40, 14, 492, "", "うげ、またあの魔物？\nさすがに今度は\n丸焼きとかはやめてよね…\n見た目がヤバすぎるし", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 36, 14, 493, "", "ふふ、キャルさまもだいぶ\n魔物肉に慣れてきたようですね\n調理ならばわたくしに\nお任せください♪", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 39, 14, 494, "", "みんな、何をしているの？\nなんだか、\n不穏な単語が聞こえたんだけど…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 40, 14, 495, "", "シェフィちゃん！\n明日の食べ尽くしツアーの\n相談をしてたんですよ！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 37, 14, 496, "", "はい。明日は【美食殿】の\n一員となったシェフィさまと一緒に\n初めて記念日を過ごすのですから\n特別なコース料理を用意しませんと", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 41, 14, 497, "", "ふふん♪\n猫の毛も逆立つような\nあれこれを食べさせられるから\n覚悟しておいたほうがいいわよ？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 40, 14, 498, "", "へ、へぇ…", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 41, 14, 499, "", "期待しててくださいね！\nシェフィちゃんとあなたに\n『おいちー！』って喜んでもらえる\n最高のごちそうを準備しますから☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 41, 14, 500, "", "ええと…その…うーんと…\nわ、分かったわ\n私も【美食殿】の一員だもの", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 42, 14, 501, "", "それにあなたも一緒みたいだし\n最後までがんばってみるわ…！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 42, 15, 502, "", "それではいつものあれを\nやりましょう！\n準備はいいですかっ？\n…いっきますよー！", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 42, 15, 503, "", "祝！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 38, 15, 504, "", "3.5周年！", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 43, 15, 505, "", "おめでとうございます！", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 14, 15, 506, "", "この日を迎えられたのも\nあなたが『プリンセスコネクト！\nRe:Dive』を遊んでくれている\nおかげです！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "カリン", 0, 190801, 15, 15, 507, "", "ということで\nみなさんからあなたへ一言ずつ\n感謝の言葉をどうぞ！", 0, 2, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 43, 15, 508, "", "感謝の言葉ですか？　わたしは\n毎日あなたに感謝してますよ\n【美食殿】の仲間になってくれて…\n一緒にごはんを食べてくれて…", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 44, 15, 509, "", "なにより今でもわたしをぺコリーヌ\nって呼んでくれてありがとうござい\nます。これからもわたしはあなたの\nぺコリーヌです！　やばいですね☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 43, 15, 510, "", "えっ！？　今度はあたし！？\n感謝って…まぁ、そうね…\nあんたにはあたしが\n辛くて苦しい時に助けてもらって…", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "キャル", 0, 106001, 44, 15, 511, "", "でもおかげで色々吹っ切れたわ！\nもしあんたが困ってたら今度は\nあたしが助けてあげるから\nその時はちゃんと言いなさいよ！", 0, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 44, 15, 512, "", "ええと…次は私ね\n実はよく覚えてないのだけど\n空から落ちてきた私を受け止めて\nくれたのはあなたなのでしょう？", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "シェフィ", 0, 106401, 45, 15, 513, "", "最初に私を見つけてくれたのが\nあなたで良かったって思ってるの\nおかげで私は居場所を見つけたから\nあなたがくれたもの、大切にするわ", 0, 0, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 39, 15, 514, "", "では最後にわたくしから…\nわたくしは主さまの元を離れた日…\nこのように記念日をお祝いする\nことは二度とないと思っていました", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 40, 15, 515, "", "ですが、主さまはわたくしを\n迎えにきてくださり、今もこうして\nおそばにおいてくださっています\nわたくしにとって毎日が記念日です", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "コッコロ", 0, 105901, 41, 15, 516, "", "わたくしたちの物語は\nまだ続いていきます\nこれからも一緒にページを\n作っていきましょうね", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "ペコリーヌ", 0, 105801, 45, 15, 517, "", "それじゃ\nいつものあれでしめますよ！\nみんなで一緒に、さんはい☆", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (80005, "みんな", 1, 105801, 46, 15, 518, "105901,42,106001,45,106401,46,190801,16", "これからも\nよろしくおねがいします！", 0, 4, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "カリン", 0, 190804, 1, 0, 519, "", "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 520, "", "今日の運勢は姫吉！　どんな不可能も可能にできちゃう！　　　　仲間と食卓を囲めばさらに運気上昇よ！　ただし魔物料理以外！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 521, "", "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 522, "", "今日の運勢は姫吉！　羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！　やってみましょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 523, "", "今日の運勢は姫吉！　精霊も新年の幸福をお祝いしています！　　主さまの笑顔が見られて、わたくしも幸せいっぱいでございます♪", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 524, "", "今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 525, "", "今日の運勢は大吉！　お裁縫好きな女の子のお墨付きです！　　　お世話したがりの妹にめいっぱい愛されちゃうかも！？", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 526, "", "今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 527, "", "今日の運勢は大吉！　ラッキーカラーは鮮やかな黄色！　　　　　さらにシマシマのアイテムを持つと、運気倍増らしいッスよ♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 528, "", "今日の運勢は大吉！　秘められた力が開花するでしょう！　　　　じゃあ、私の龍眼と力比べしてみようか？　ふふ、冗談だよ～", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 529, "", "今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 530, "", "今日の運勢は中吉！　家の中でゆっくり過ごすのがよさそう！　　ラッキーアイテムはゲームよ！　ベストスコアを更新できるかも？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 531, "", "今日の運勢は中吉！　上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 532, "", "今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 533, "", "今日の運勢は中吉！　日頃の努力が報われます！　　　　　　　　親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 534, "", "今日の運勢は中吉！　ラッキーアイテムはかわいいもの！　　　　ア、アタシはかわいいじゃなくてキレイだってば！　も～っ！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 535, "", "今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 536, "", "今日の運勢は中吉！　悩まず行動すれば強運に恵まれる！　　　　守るよりも攻めるが吉だ！　勝負事をするにはいい運勢だな！", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 537, "", "今日の運勢は小吉！　まだ見ぬ危険が隠れているかも！　　　　　でも安心しろ！　提督が貴公を守ってくれるはずだぞ！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 538, "", "今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 539, "", "今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 540, "", "今日の運勢は小吉！　難しい頼み事をされるかもしれません！　　うまくやれればきっと成長につながります、挑戦してみましょう！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 541, "", "今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 542, "", "今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "", 0, 0, 0, 0, 543, "", "今日の運勢は小吉！　無理は禁物、お家で静かにしていましょう　プロぼっちの私が、お家での過ごし方……教えてあげましょうか？", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "カリン", 0, 190804, 2, 0, 544, "", "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60003, "カリン", 0, 190804, 3, 7, 545, "", "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "カリン", 0, 190804, 1, 0, 546, "", "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 547, "", "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 548, "", "今日の運勢は姫吉！　羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！　やってみましょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 549, "", "今日の運勢は姫吉！　宴でも開きたくなるほどの絶対幸運！\nイメチェンでもしてみるのはどうだ？　ぴょんぴょん、なんてな♪", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 550, "", "今日の運勢は姫吉！　ずっと祈り続けていた願いが叶うかも！\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 551, "", "今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 552, "", "今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 553, "", "今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 554, "", "今日の運勢は大吉！　ラッキーワードは「ぴょんぴょん♪」\nおっきな声で一緒に言ってみよ～♪　うさぎさんぴょんぴょ～ん♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 555, "", "今日の運勢は大吉！　あなたの趣味がもっと広がるかも！\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 556, "", "今日の運勢は大吉！　秘められた力が開花するでしょう！　　　　じゃあ、私の龍眼と力比べしてみようか？　ふふ、冗談だよ～", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 557, "", "今日の運勢は中吉！　ラッキーアイテムはかわいいもの！　　　　ア、アタシはかわいいじゃなくてキレイだってば！　も～っ！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 558, "", "今日の運勢は中吉！　悩まず行動すれば強運に恵まれる！　　　　守るよりも攻めるが吉だ！　勝負事をするにはいい運勢だな！", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 559, "", "今日の運勢は中吉！　お出かけした先で良縁に恵まれそうです！　ダウナー系あざとい女子が、あま～い飴をくれるかも？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 560, "", "今日の運勢は中吉！　大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 561, "", "今日の運勢は中吉！　健康に気を遣って気持ちのいい一年を！\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 562, "", "今日の運勢は中吉！　歌を口ずさみ、幸運を呼び込もう！\n幸運になれるかは分からないけど……一緒に、歌いましょ？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 563, "", "今日の運勢は中吉！　誰かに尽くすことで掴める幸せもあるかも？\n人事を尽くして天命を待つ！　さ、年始もバリバリ働きますわよ♪", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 564, "", "今日の運勢は小吉！　難しい頼み事をされるかもしれません！　　うまくやれればきっと成長につながります、挑戦してみましょう！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 565, "", "今日の運勢は小吉！　無理は禁物、お家で静かにしていましょう　プロぼっちの私が、お家での過ごし方……教えてあげましょうか？", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 566, "", "今日の運勢は小吉！　思わぬ相手と仲良くなれるかも？　　　　　うっかり毒舌をもらしてしまわないように要注意です！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 567, "", "今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 568, "", "今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 569, "", "今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "", 0, 0, 0, 0, 570, "", "今日の運勢は小吉！　小さな勇気で踏み出す一歩が大事！\n遠くから見てるだけじゃダメ。今日は、少しだけ近づいてみます！", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "カリン", 0, 190804, 2, 0, 571, "", "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60004, "カリン", 0, 190804, 3, 7, 572, "", "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "カリン", 0, 190804, 1, 0, 573, "", "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 574, "", "今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 575, "", "今日の運勢は姫吉！　ずっと祈り続けていた願いが叶うかも！\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に", 1, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 576, "", "今日の運勢は姫吉！　道を歩けば幸運に当たる、最高の吉日！　　さすがは兄様。尽善尽美、金甌無欠の強運をお持ちですね。", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 577, "", "今日の運勢は姫吉！　旅立ち、どこへ行くもよし！　　　　　　　新年の門出も、お兄さんと一緒です♪　冒険にしゅっぱーつ♪", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 578, "", "今日の運勢は姫吉！　一日三食食べれば健康運アップ！　　　　　おせち。おぞうに。もっと、たべよ？　お兄。", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 579, "", "今日の運勢は大吉！　あなたの趣味がもっと広がるかも！\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 580, "", "今日の運勢は大吉！　お裁縫好きな女の子のお墨付きです！　　　お世話したがりの妹にめいっぱい愛されちゃうかも！？", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 581, "", "今日の運勢は大吉！　日々の努力が実り、何事も良い方向へ！　　そんな弟くんには、お姉ちゃんのよしよしぎゅ～っをプレゼント♪", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 582, "", "今日の運勢は大吉！　お出かけするといいことあるかも？　　　　また一緒に、お忍びデートしてくださいね……騎士♪", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 583, "", "今日の運勢は大吉！　転居するならあたたかい場所が吉！　　　　煉獄の世なれど、住めば都と申しんす。ゆるりときなんせ……♪", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 584, "", "今日の運勢は中吉！　大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 585, "", "今日の運勢は中吉！　誰かに尽くすことで掴める幸せもあるかも？\n人事を尽くして天命を待つ！　さ、年始もバリバリ働きますわよ♪", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 586, "", "今日の運勢は中吉！　歌を口ずさみ、幸運を呼び込もう！\n幸運になれるかは分からないけど……一緒に、歌いましょ？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 587, "", "今日の運勢は中吉！　健康に気を遣って気持ちのいい一年を！\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 588, "", "今日の運勢は中吉！　旅行運がぐんぐんと上昇中♪　　　　　　　もしかしたら、あの「マホマホ王国」にだって行けるかも♪", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 589, "", "今日の運勢は中吉！　争いごとは勝つが油断は大敵！　　　　　　ま、このあたしと一緒なら、向かうところ敵はねーですよっ！", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 590, "", "今日の運勢は中吉！　ラッキーアイテムは「光るもの」！　　　　ハツネちゃんの「きらーんっ☆」な魔法、見せちゃおうかなっ？", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 591, "", "今日の運勢は小吉！　のんびり穏やかな一日となるでしょう！　　あなた様を邪魔するものは全てエリコが排除しますわ、クスクス♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 592, "", "今日の運勢は小吉！　小さな勇気で踏み出す一歩が大事！\n遠くから見てるだけじゃダメ。今日は、少しだけ近づいてみます！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 593, "", "今日の運勢は小吉！　外に出てゆっくり過ごすと運気が上昇！　　ラッキースポットは牧場。面白い出会いがありそうです♪", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 594, "", "今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 595, "", "今日の運勢は小吉！　難しい頼み事をされるかもしれません！　　うまくやれればきっと成長につながります、挑戦してみましょう！", 1, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 596, "", "今日の運勢は小吉！　空を眺めると気持ちが晴れやかに！　　　　眺めるだけじゃなくて、ひとっ飛びしちゃいましょうかっ♪", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "", 0, 0, 0, 0, 597, "", "今日の運勢は小吉！　掃除をすると運勢が開けそう！　　　　　　「わ、めんど」「ヴルムっ！　新年早々サボっちゃダメなんだからね！」", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "カリン", 0, 190804, 2, 0, 598, "", "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60005, "カリン", 0, 190804, 3, 7, 599, "", "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "カリン", 0, 190804, 1, 0, 600, "", "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 601, "", "今日の運勢は姫吉！　勇気を持って、新しいことに挑戦しよう！\n幸先がいいねえ少年！　今年もいい一年になるよう祈ってるよ。", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 602, "", "今日の運勢は姫吉！　どんなピンチも簡単に乗り越えられそう！\nよい結果が出たようで何よりです。さて、待人の方は……ふふ。", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 603, "", "今日の運勢は姫吉！　あの人と仲直り……できちゃうかも！？\nはあ……この私があなたの運勢に興味を抱くわけないでしょう？", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 604, "", "今日の運勢は大吉！　身近な友達との絆が深まる予感……？\n騎士様は、どなたと友誼を結ぶのでしょう？　気になります……", 1, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 605, "", "今日の運勢は大吉！　ラッキーアイテムは「蛇の抜け殻」！\nこのアタシにお目にかかれるなんて……アンタ、幸せものね♪", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 606, "", "今日の運勢は中吉！　気になるあの人に会えちゃうかも！？\n『初夢を正夢にする枕』であなたに会え……な、なんでもない！", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 607, "", "今日の運勢は中吉！　子供に戻って、一日中遊びつくそう！\nお年玉でけん玉ゲット！　おじちゃん、もしかめ一万回やって！", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 608, "", "今日の運勢は中吉！　今日はおうちで、ゆーっくりくつろごう。\nお雑煮よし。みかんよし。さ、こたつで寝正月だ。君も入る？", 1, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 609, "", "今日の運勢は小吉！　突然のドッキリに注意！\nおや、後ろに髪の長い女の霊が──フフ、冗談です。私ですよ。", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "", 0, 0, 0, 0, 610, "", "今日の運勢は小吉。慌てなくても、幸運はきっとやってくる。\n運は自分で掴むもの──媛が言ってました。でも、どうやって？", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "カリン", 0, 190804, 2, 0, 611, "", "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60006, "カリン", 0, 190804, 3, 5, 612, "", "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "カリン", 0, 190804, 1, 0, 613, "", "新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", 1, 1, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 614, "", "今日の運勢は姫吉！　絶好調で最高の一日になりそう♪\nわたしも、騎士クンが一緒ならいつだって最高に幸せな日だよ……", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 615, "", "今日の運勢は姫吉！　新しいことに挑戦するチャンス！\nお姉さんも一緒に挑戦しちゃおっかな♪　飲み処の新規開拓とか！", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 616, "", "今日の運勢は姫吉！　日々の努力が実を結ぶ予感！\n今日一日鍛錬に勤しむべき、ということだな。では早速行こうか。", 2, 2, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 617, "", "今日の運勢は大吉！　家族サービスにはぴったりの日！\nさっそく弟くんにあまあまお姉ちゃんの出血大サービス、だよっ♪", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 618, "", "今日の運勢は大吉！　笑顔で過ごせば周りもみんなハッピーかも！\n『笑う顔はフグになる』ですねっ。幸せいっぱいお届けしますっ", 2, 2, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 619, "", "今日の運勢は中吉！　恋愛運良し、積極的な行動に成果が！？\nじゃあ騎士さんのこと、拉致しちゃうとか★　恋愛成就確定です♥", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 620, "", "今日の運勢は中吉！　おめかししたら運気も上昇？\n毛並がふわふわになるまでブラッシングしたわ♪　ふふ、完璧ね！", 2, 2, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 621, "", "今日の運勢は小吉！　知らない場所に行くと新たな発見が！\n未知の場所……一人では恐ろしくて。騎士さま、どうかお力添えを", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "", 0, 0, 0, 0, 622, "", "今日の運勢は小吉！　ラッキーアイテムは鳥の羽根！\nだからって、私の羽を毟ろうとしないでくださ～いっ！", 2, 2, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "カリン", 0, 190804, 2, 0, 623, "", "おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", 0, 3, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES (60007, "カリン", 0, 190804, 3, 5, 624, "", "おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", 0, 3, 0);
